#include <stdio.h>
#include <stdlib.h>

int minMoves(int* arr, int n) {
    int* visited = (int*)calloc(n, sizeof(int));
    int moves = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            int j = i;
            while (!visited[j]) {
                visited[j] = 1;
                j = arr[j] - 1;
            }
            moves++;
        }
    }
    free(visited);
    return n - moves;
}

int main() {
    int n;
    scanf("%d", &n);
    int* arr = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    printf("%d\n", minMoves(arr, n));
    free(arr);
    return 0;
}

