#include <iostream>
using namespace std;

int minMoves(int arr[], int n) {
    bool* visited = new bool[n];
    int moves = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            int j = i;
            while (!visited[j]) {
                visited[j] = true;
                j = arr[j] - 1;
            }
            moves++;
        }
    }
    delete[] visited;
    return n - moves;
}

int main() {
    int n;
    cin >> n;
    int* arr = new int[n];
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    cout << minMoves(arr, n) << endl;
    delete[] arr;
    return 0;
}

